import { readFileSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const root = resolve(here, '..');
const wrapper = readFileSync(resolve(root, 'src/bootstrap/templates/bootstrap-wrapper.mjs'), 'utf8');
const inner = readFileSync(resolve(root, 'src/bootstrap/templates/bootstrap-inner.mjs'), 'utf8');

const output = [
  '// Generated by packages/core/scripts/embed-bootstrap-templates.mjs. Do not edit by hand.',
  '',
  'export const BOOTSTRAP_WRAPPER_TEMPLATE = ' + JSON.stringify(wrapper) + ';',
  '',
  'export const BOOTSTRAP_INNER_TEMPLATE = ' + JSON.stringify(inner) + ';',
  '',
].join('\n');

writeFileSync(resolve(root, 'src/bootstrap/templates.generated.ts'), output, 'utf8');
